      "path": "src/modules/projects/routes.js",
      "content": "const express = require('express');
const projectsService = require('./service');
const { sendError } = require('../../lib/errors');

const router = express.Router();

router.post('/', async (req, res) => {
  const { name } = req.body;
  if (!name) {
    return sendError(res, 400, 'INVALID_NAME', 'Name is required');
  }
  try {
    const project = await projectsService.createProject(name);
    res.status(201).json({ project });
  } catch (error) {
    if (error.code === 'PROJECT_EXISTS') {
      return sendError(res, 409, 'PROJECT_EXISTS', 'Project already exists');
    }
    sendError(res, 500, 'INTERNAL_ERROR', 'Internal server error');
  }
});

router.get('/', async (req, res) => {
  try {
    const projects = await projectsService.getAllProjects();
    res.json({ projects });
  } catch (error) {
    sendError(res, 500, 'INTERNAL_ERROR', 'Internal server error');
  }
});

module.exports = router;"
    },
    {
      "path": "src/modules/projects/service.js",
      "content": "const { generateId } = require('../../lib/id');

let projectsStore = [];

const createProject = async (name) => {
  if (projectsStore.some(project => project.name === name)) {
    throw new Error('PROJECT_EXISTS');
  }
  const project = { id: generateId(), name };
  projectsStore.push(project);
  return project;
};

const getAllProjects = async () => {
  return projectsStore;
};

module.exports = { createProject, getAllProjects };"
