    {
      "path": "src/modules/tasks/routes.js",
      "content": "const express = require('express');
const tasksService = require('./service');
const { sendError } = require('../../lib/errors');

const router = express.Router();

router.post('/', async (req, res) => {
  const { title } = req.body;
  if (!title) {
    return sendError(res, 400, 'INVALID_TITLE', 'Title is required');
  }
  try {
    const task = await tasksService.createTask(req.params.projectId, title);
    res.status(201).json({ task });
  } catch (error) {
    sendError(res, 500, 'INTERNAL_ERROR', 'Internal server error');
  }
});

router.get('/', async (req, res) => {
  const { status } = req.query;
  try {
    const tasks = await tasksService.getAllTasks(req.params.projectId, status);
    res.json({ tasks });
  } catch (error) {
    sendError(res, 500, 'INTERNAL_ERROR', 'Internal server error');
  }
});

router.patch('/:taskId/comments', async (req, res) => {
  const { status } = req.body;
  if (!['todo', 'done'].includes(status)) {
    return sendError(res, 400, 'INVALID_STATUS', 'Invalid task status');
  }
  try {
    const task = await tasksService.updateTaskStatus(req.params.projectId, req.params.taskId, status);
    res.json({ task });
  } catch (error) {
    if (error.message === 'Task not found') {
      return sendError(res, 404, 'TASK_NOT_FOUND', 'Task not found');
    }
    sendError(res, 500, 'INTERNAL_ERROR', 'Internal server error');
  }
});

module.exports = router;"
    },
    {
      "path": "src/modules/tasks/service.js",
      "content": "const { generateId } = require('../../lib/id');

let tasksStore = [];

const createTask = async (projectId, title) => {
  const task = { id: generateId(), projectId, title, status: 'todo' };
  tasksStore.push(task);
  return task;
};

const getAllTasks = async (projectId, status) => {
  let tasks = tasksStore.filter(task => task.projectId === projectId);
  if (status) {
    tasks = tasks.filter(task => task.status === status);
  }
  return tasks;
};

const updateTaskStatus = async (projectId, taskId, status) => {
  const task = tasksStore.find(task => task.id === taskId && task.projectId === projectId);
  if (!task) {
    throw new Error('Task not found');
  }
  task.status = status;
  return task;
};

module.exports = { createTask, getAllTasks, updateTaskStatus };"
