      "content": "let membersStore = [];

const addMember = async (projectId, userId, role) => {
  if (membersStore.some(member => member.projectId === projectId && member.userId === userId)) {
    throw new Error('MEMBER_EXISTS');
  }
  const member = { projectId, userId, role };
  membersStore.push(member);
  return member;
};

module.exports = { addMember };"
